vanillaJS.formSubmit:
(function () {
  var form = document.getElementById('estimate-form');
  var success = document.getElementById('form-success');
  if (!form || !success) return;

  form.addEventListener('submit', function (e) {
    e.preventDefault();
    var data = new FormData(form);
    fetch('/', {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams(data).toString()
    })
      .then(function (res) {
        if (res.ok) {
          form.hidden = true;
          success.hidden = false;
          success.scrollIntoView({ behavior: 'smooth', block: 'center' });
        } else {
          throw new Error('Network response was not ok: ' + res.status);
        }
      })
      .catch(function (err) {
        console.error('Form submission error:', err);
        // Fallback: let the browser handle native submission
        form.submit();
      });
  });
})();

vanillaJS.headerScroll:
(function () {
  var header = document.getElementById('site-header');
  if (!header) return;

  // Create a 1px sentinel div at the very top of <body>
  var sentinel = document.createElement('div');
  sentinel.style.cssText = 'position:absolute;top:0;left:0;width:1px;height:1px;pointer-events:none;';
  sentinel.setAttribute('aria-hidden', 'true');
  document.body.insertBefore(sentinel, document.body.firstChild);

  var observer = new IntersectionObserver(
    function (entries) {
      entries.forEach(function (entry) {
        if (entry.isIntersecting) {
          header.classList.remove('header--scrolled');
        } else {
          header.classList.add('header--scrolled');
        }
      });
    },
    { threshold: 0 }
  );

  observer.observe(sentinel);

  // CSS expected in stylesheet:
  // #site-header { height: 80px; transition: height 0.2s ease, box-shadow 0.2s ease; }
  // #site-header.header--scrolled { height: 60px; box-shadow: 0 2px 8px rgba(0,0,0,0.12); }
})();

vanillaJS.mobileMenu:
(function () {
  var toggle = document.getElementById('mobile-menu-toggle');
  var menu = document.getElementById('mobile-menu');
  if (!toggle || !menu) return;

  toggle.addEventListener('click', function () {
    var isOpen = menu.getAttribute('aria-hidden') === 'false';
    menu.setAttribute('aria-hidden', isOpen ? 'true' : 'false');
    toggle.setAttribute('aria-expanded', isOpen ? 'false' : 'true');
    menu.classList.toggle('mobile-menu--open', !isOpen);
    document.body.classList.toggle('menu-open', !isOpen);
  });

  // Close menu on outside click
  document.addEventListener('click', function (e) {
    if (
      menu.classList.contains('mobile-menu--open') &&
      !menu.contains(e.target) &&
      !toggle.contains(e.target)
    ) {
      menu.setAttribute('aria-hidden', 'true');
      toggle.setAttribute('aria-expanded', 'false');
      menu.classList.remove('mobile-menu--open');
      document.body.classList.remove('menu-open');
    }
  });

  // Close menu on Escape key
  document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape' && menu.classList.contains('mobile-menu--open')) {
      menu.setAttribute('aria-hidden', 'true');
      toggle.setAttribute('aria-expanded', 'false');
      menu.classList.remove('mobile-menu--open');
      document.body.classList.remove('menu-open');
      toggle.focus();
    }
  });
})();

vanillaJS.faqAccordion:
(function () {
  var items = document.querySelectorAll('[data-faq-item]');
  if (!items.length) return;

  items.forEach(function (item) {
    var trigger = item.querySelector('[data-faq-trigger]');
    var panel = item.querySelector('[data-faq-panel]');
    if (!trigger || !panel) return;

    // Set initial ARIA state
    var panelId = panel.id || ('faq-panel-' + Math.random().toString(36).slice(2));
    panel.id = panelId;
    trigger.setAttribute('aria-controls', panelId);
    trigger.setAttribute('aria-expanded', 'false');
    panel.setAttribute('aria-hidden', 'true');
    panel.style.maxHeight = '0';
    panel.style.overflow = 'hidden';
    panel.style.transition = 'max-height 0.25s ease, opacity 0.25s ease';
    panel.style.opacity = '0';

    trigger.addEventListener('click', function () {
      var isOpen = trigger.getAttribute('aria-expanded') === 'true';

      // Close all other panels
      items.forEach(function (other) {
        var otherTrigger = other.querySelector('[data-faq-trigger]');
        var otherPanel = other.querySelector('[data-faq-panel]');
        if (otherTrigger && otherPanel && otherTrigger !== trigger) {
          otherTrigger.setAttribute('aria-expanded', 'false');
          otherPanel.setAttribute('aria-hidden', 'true');
          otherPanel.style.maxHeight = '0';
          otherPanel.style.opacity = '0';
          other.classList.remove('faq-item--open');
        }
      });

      // Toggle current
      if (isOpen) {
        trigger.setAttribute('aria-expanded', 'false');
        panel.setAttribute('aria-hidden', 'true');
        panel.style.maxHeight = '0';
        panel.style.opacity = '0';
        item.classList.remove('faq-item--open');
      } else {
        trigger.setAttribute('aria-expanded', 'true');
        panel.setAttribute('aria-hidden', 'false');
        panel.style.maxHeight = panel.scrollHeight + 'px';
        panel.style.opacity = '1';
        item.classList.add('faq-item--open');
      }
    });
  });
})();
